import{_ as n,c as a,o as t,a1 as i}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Häufige Fragen: Problemlösung | opencode-plannotator","description":"Lernen Sie Lösungen für häufige Probleme mit Plannotator kennen. Beherrschen Sie schnelle Fehlerbehebungsmethoden für Port-Konflikte, nicht geöffnete Browser und Integrationsfehler.","frontmatter":{"title":"Häufige Fragen: Problemlösung | opencode-plannotator","sidebarTitle":"Problemlösung","subtitle":"Häufige Fragen: Problemlösung","description":"Lernen Sie Lösungen für häufige Probleme mit Plannotator kennen. Beherrschen Sie schnelle Fehlerbehebungsmethoden für Port-Konflikte, nicht geöffnete Browser und Integrationsfehler.","order":4},"headers":[],"relativePath":"de/backnotprop/plannotator/faq/index.md","filePath":"de/backnotprop/plannotator/faq/index.md"}'),r={name:"de/backnotprop/plannotator/faq/index.md"};function l(s,e,o,h,d,u){return t(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="haufige-fragen" tabindex="-1">Häufige Fragen <a class="header-anchor" href="#haufige-fragen" aria-label="Permalink to &quot;Häufige Fragen&quot;">​</a></h1><p>Dieses Kapitel hilft Ihnen, verschiedene Probleme bei der Verwendung von Plannotator zu lösen. Egal ob Port-Konflikte, nicht geöffnete Browser oder Integrationsfehler – hier finden Sie entsprechende Lösungen und Debugging-Tipps.</p><h2 id="inhalt-dieses-kapitels" tabindex="-1">Inhalt dieses Kapitels <a class="header-anchor" href="#inhalt-dieses-kapitels" aria-label="Permalink to &quot;Inhalt dieses Kapitels&quot;">​</a></h2><div class="grid-cards"><a href="./common-problems/" class="card"><h3>🔧 Häufige Probleme</h3><p>Lösen Sie häufige Probleme während der Verwendung, einschließlich Port-Konflikten, nicht geöffneten Browsern, nicht angezeigten Plänen, Git-Fehlern, fehlgeschlagenen Bild-Uploads sowie Problemen mit Obsidian- und Bear-Integration.</p></a><a href="./troubleshooting/" class="card"><h3>🔍 Fehlerbehebung</h3><p>Beherrschen Sie grundlegende Fehlerbehebungsmethoden, einschließlich Protokollanzeige, Fehlerbehandlung und Debugging-Techniken. Lernen Sie, Probleme schnell durch Protokollausgaben zu lokalisieren.</p></a></div><h2 id="lernpfad" tabindex="-1">Lernpfad <a class="header-anchor" href="#lernpfad" aria-label="Permalink to &quot;Lernpfad&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Häufige Fragen → Fehlerbehebung</span></span>
<span class="line"><span>      ↓               ↓</span></span>
<span class="line"><span>  Schnelle Lösung    Tiefes Debugging</span></span></code></pre></div><p><strong>Empfohlene Reihenfolge</strong>:</p><ol><li><strong>Zuerst die häufigen Probleme ansehen</strong>: Die meisten Probleme finden hier sofortige Lösungen</li><li><strong>Dann die Fehlerbehebung lernen</strong>: Wenn häufige Probleme nicht abgedeckt sind, lernen Sie, wie Sie Protokolle und Debugging-Techniken zur eigenständigen Fehlerbehebung nutzen</li></ol><div class="tip custom-block"><p class="custom-block-title">Tipp bei Problemen</p><p>Suchen Sie zunächst in den &quot;Häufigen Fragen&quot; nach Schlüsselwörtern (z. B. &quot;Port&quot;, &quot;Browser&quot;, &quot;Obsidian&quot;) und finden Sie entsprechende Lösungen. Bei komplexeren oder nicht gelisteten Problemen konsultieren Sie bitte die &quot;Fehlerbehebung&quot;, um Debugging-Methoden zu lernen.</p></div><h2 id="voraussetzungen" tabindex="-1">Voraussetzungen <a class="header-anchor" href="#voraussetzungen" aria-label="Permalink to &quot;Voraussetzungen&quot;">​</a></h2><p>Bevor Sie dieses Kapitel durchgehen, sollten Sie Folgendes abgeschlossen haben:</p><ul><li>✅ <a href="./../start/getting-started/">Erste Schritte</a> - Grundlegende Konzepte von Plannotator verstehen</li><li>✅ Installation des Claude Code- oder OpenCode-Plugins (eines von beiden): <ul><li><a href="./../start/installation-claude-code/">Claude Code Plugin installieren</a></li><li><a href="./../start/installation-opencode/">OpenCode Plugin installieren</a></li></ul></li></ul><h2 id="nachste-schritte" tabindex="-1">Nächste Schritte <a class="header-anchor" href="#nachste-schritte" aria-label="Permalink to &quot;Nächste Schritte&quot;">​</a></h2><p>Nach Abschluss dieses Kapitels können Sie Folgendes lernen:</p><ul><li><a href="./../appendix/api-reference/">API-Referenz</a> - Alle API-Endpunkte und Anfrage-/Antwortformate verstehen</li><li><a href="./../appendix/data-models/">Datenmodelle</a> - Die vom Plannotator verwendeten Datenstrukturen verstehen</li><li><a href="./../advanced/environment-variables/">Umgebungsvariablen-Konfiguration</a> - Alle verfügbaren Umgebungsvariablen im Detail kennenlernen</li></ul>`,15)])])}const p=n(r,[["render",l]]);export{c as __pageData,p as default};
